from celery import Celery

celery_app = Celery(
    "agent_runner",
    broker="redis://localhost:6379/0",
    backend="redis://localhost:6379/0"
)

@celery_app.task(bind=True)
def run_agent_task(self, prompt: str):
    self.update_state(state="RUNNING", meta={"step": "calling_claude"})
    result = {"output": f"Processed: {prompt}"}
    return result

@celery_app.task(bind=True)
def run_agent_task(self, run_id: str):
    state = load_run_state(run_id)

    while state["status"] not in {"completed", "failed", "cancelled"}:
        model_output = call_claude(state)
        event = decide_next_step(model_output)

        persist_event(run_id, event)

        if event["type"] == "tool_call":
            tool_result = execute_tool(event["tool"], event["args"])
            persist_tool_result(run_id, tool_result)
            state = update_state(state, tool_result)

        elif event["type"] == "final":
            persist_output(run_id, event["content"])
            mark_completed(run_id)
            break
